exercise.solution:
const grades = [85, 42, 91, 67, 73, 55, 88];

// 1. Print every grade
for (const grade of grades) {
  console.log(grade);
}

// 2. Print only passing grades
for (const grade of grades) {
  if (grade < 70) continue;
  console.log(`Passing: ${grade}`);
}
// Passing: 85
// Passing: 91
// Passing: 73
// Passing: 88

// 3. Print each grade with its 1-based position
for (let i = 0; i < grades.length; i++) {
  console.log(`${i + 1}: ${grades[i]}`);
}
// 1: 85
// 2: 42
// 3: 91
// 4: 67
// 5: 73
// 6: 55
// 7: 88
